const dayOfWeek = $now.toJSDate().getDay();

const schedule = {
  0: { topic: 'Week in AI Roundup', section_label: 'Weekly Recap' },
  1: { topic: 'AI News & Breakthroughs', section_label: 'Monday Briefing' },
  2: { topic: 'Healthcare AI & Hospital Tech', section_label: 'Healthcare Focus' },
  3: { topic: 'AI Startups & Funding', section_label: 'Startup Watch' },
  4: { topic: 'AI Regulation & Policy', section_label: 'Policy Desk' },
  5: { topic: 'AI News & Breakthroughs', section_label: 'Friday Drops' },
  6: { topic: 'Healthcare AI Deep Dive', section_label: 'Saturday Deep Dive' }
};

const today = schedule[dayOfWeek];

return [{ json: {
  topic: today.topic,
  section_label: today.section_label,
  triggered_by: 'FutureFrames AI Auto-scheduler',
  channel_id: 'YOUR_DEFAULT_SLACK_CHANNEL_ID',
  timestamp: $now.format('yyyy-MM-dd')
}}];

const allItems = $input.all();

const articles = allItems.map(item => {
  const j = item.json;
  return {
    title: j.title || j.name || '',
    description: j.contentSnippet || j.description || j.content || j.snippet || '',
    source: j.source?.name || j.source?.url || j.source || j.creator || '',
    url: j.url || j.link || '',
    publishedAt: j.publishedAt || j.pubDate || j.isoDate || j.published_at || '',
    fullContent: j.content || j.contentSnippet || j.description || ''
  };
}).filter(a => a.title && a.title.length > 5);

const seen = new Set();
const unique = [];
for (const a of articles) {
  const key = a.title.toLowerCase().substring(0, 80);
  if (key && !seen.has(key)) { seen.add(key); unique.push(a); }
}

return unique.slice(0, 20).map(a => ({ json: a }));

try {
  let text = $input.first().json.text;
  text = text.trim();
  text = text.replace(/```json\s*/gi, '');
  text = text.replace(/```\s*/g, '');
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start === -1 || end === -1) throw new Error('No JSON object found');
  text = text.substring(start, end + 1);
  const parsed = JSON.parse(text);
  let meta = {};
  try { meta = $('Set — From Slack').first().json; } catch(e1) {
    try { meta = $('Daily Topic Rotation').first().json; } catch(e2) { meta = {}; }
  }
  parsed.topic = meta.topic || parsed.top_story_title || 'AI Update';
  parsed.triggered_by = meta.triggered_by || 'Auto-scheduler';
  parsed.channel_id = meta.channel_id || '';
  parsed.timestamp = meta.timestamp || $now.format('yyyy-MM-dd');
  parsed.section_label = meta.section_label || 'Daily Briefing';
  return [{ json: parsed }];
} catch (e) {
  return [{ json: { error: true, message: 'Parse failed: ' + e.message, raw: $input.first().json.text } }];
}
